import{_ as a,o as i,c as s,a2 as t}from"./chunks/framework.BKG_UbFK.js";const u=JSON.parse('{"title":"Super Admin","description":"","frontmatter":{},"headers":[],"relativePath":"it/features/super-admin.md","filePath":"it/features/super-admin.md"}'),o={name:"it/features/super-admin.md"};function l(n,e,r,c,d,p){return i(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="super-admin" tabindex="-1">Super Admin <a class="header-anchor" href="#super-admin" aria-label="Permalink to &quot;Super Admin&quot;">​</a></h1><p>Il ruolo <code>super_admin</code> viene creato automaticamente da <code>clearance:install</code> e mantenuto sincronizzato con tutti i permessi <code>clearance-*</code>.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Install and make user ID 1 a super admin</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --user=1</span></span></code></pre></div><p>Vedi la <a href="/clearance-docs/it/guide/installation.html">guida all&#39;installazione</a> e il <a href="/clearance-docs/it/api/artisan-commands.html">riferimento dei comandi Artisan</a> per l&#39;elenco completo dei flag dell&#39;installer.</p><h2 id="bypass-del-gate-opzionale" tabindex="-1">Bypass del Gate (opzionale) <a class="header-anchor" href="#bypass-del-gate-opzionale" aria-label="Permalink to &quot;Bypass del Gate (opzionale)&quot;">​</a></h2><p><code>super_admin_gate_bypass</code> controlla se il ruolo <code>super_admin</code> bypassa tutti i controlli Laravel <code>can()</code> / <code>Gate::allows()</code> / delle policy a livello globale, tramite un hook <code>Gate::before()</code>. Predefinito: <code>false</code>. Il bypass è opzionale. Per abilitarlo:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;super_admin_gate_bypass&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span></code></pre></div><div class="danger custom-block"><p class="custom-block-title">A livello di applicazione, non limitato al pannello</p><p>Quando abilitato, qualsiasi utente che detiene <code>super_admin</code> salta <strong>tutti</strong> i controlli Gate a livello di applicazione - non solo i controlli del pannello Clearance. Questo interessa ogni <code>can()</code>, <code>Gate::allows()</code>, e controllo di policy nella tua applicazione, non solo quelli definiti da Clearance. Per un ambito più ristretto, lascialo disattivato e concedi i permessi esplicitamente.</p></div><h2 id="rilevamento-degli-alias" tabindex="-1">Rilevamento degli alias <a class="header-anchor" href="#rilevamento-degli-alias" aria-label="Permalink to &quot;Rilevamento degli alias&quot;">​</a></h2><p>Se il tuo database contiene già un ruolo chiamato <code>super_admin</code>, <code>superadmin</code>, <code>super-admin</code>, <code>root</code>, o <code>owner</code>, l&#39;installer lo rileva e ti chiede interattivamente se promuoverlo o creare un <code>super_admin</code> separato. Usa <code>--super-admin-role=NAME</code> per saltare il prompt:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --super-admin-role=owner</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">La promozione è non distruttiva</p><p>La promozione rinomina il ruolo sul posto - tutte le assegnazioni <code>model_has_roles</code> esistenti vengono preservate tramite la FK su <code>role_id</code>. Nessun utente perde la propria assegnazione di ruolo esistente durante la promozione.</p></div><h2 id="accesso-al-pannello-e-permessi-di-scrittura-granulari" tabindex="-1">Accesso al pannello e permessi di scrittura granulari <a class="header-anchor" href="#accesso-al-pannello-e-permessi-di-scrittura-granulari" aria-label="Permalink to &quot;Accesso al pannello e permessi di scrittura granulari&quot;">​</a></h2><p>Naviga verso <code>/clearance</code> dopo l&#39;installazione. L&#39;accesso in lettura all&#39;intero pannello richiede il permesso <code>clearance-access</code>, verificato tramite <code>can()</code>, mai <code>hasRole()</code>:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-access&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>Le operazioni di scrittura su ogni sezione sono protette da un permesso dedicato e delegabile - tutti creati da <code>clearance:install</code> e assegnati a <code>super_admin</code>:</p><table tabindex="0"><thead><tr><th>Permesso</th><th>Controlla</th></tr></thead><tbody><tr><td><code>clearance-permissions-write</code></td><td>Creazione / modifica / eliminazione dei permessi</td></tr><tr><td><code>clearance-roles-write</code></td><td>Creazione / modifica / eliminazione dei ruoli e delle loro assegnazioni di permessi</td></tr><tr><td><code>clearance-guards-write</code></td><td>Creazione / modifica / eliminazione delle guardie</td></tr><tr><td><code>clearance-settings-write</code></td><td>Modifica dei metadati di visualizzazione, icone, colori, ruolo predefinito</td></tr><tr><td><code>clearance-users-write</code></td><td>Assegnazione / rimozione dei ruoli per uno specifico utente</td></tr></tbody></table><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Grant a user write access to roles only:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-access&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-roles-write&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Concedere un accesso ristretto</p><p>Combina <code>clearance-access</code> con esattamente un permesso <code>clearance-{section}-write</code> per dare a un utente (ad esempio, un team lead) accesso in scrittura a una singola sezione del pannello - i ruoli, ad esempio - senza esporre impostazioni, guardie, o gestione utenti.</p></div><p>Se una riga di permesso granulare non esiste affatto nel database (uno stato legacy pre-seeding), il controllo ricade su <code>clearance-access</code> per retrocompatibilità. Su qualsiasi istanza che ha eseguito <code>clearance:install</code>, questo fallback non si attiva mai.</p><h2 id="permessi-clearance-riservati" tabindex="-1">Permessi <code>clearance-*</code> riservati <a class="header-anchor" href="#permessi-clearance-riservati" aria-label="Permalink to &quot;Permessi \`clearance-*\` riservati&quot;">​</a></h2><p>I permessi <code>clearance-*</code> sono riservati: non possono essere creati, rinominati, eliminati, o aggiunti a nessun ruolo se non attraverso il flusso di installazione proprio del pacchetto - nemmeno da un attore <code>super_admin</code> per il ruolo <code>super_admin</code> stesso.</p><h2 id="prossimi-passi" tabindex="-1">Prossimi passi <a class="header-anchor" href="#prossimi-passi" aria-label="Permalink to &quot;Prossimi passi&quot;">​</a></h2><ul><li><a href="/clearance-docs/it/features/permissions.html">Permissions</a> - il pannello CRUD generale dei permessi (esclude <code>clearance-*</code>).</li><li><a href="/clearance-docs/it/features/roles.html">Roles</a> - assegnare i permessi <code>clearance-*-write</code> a un ruolo personalizzato.</li><li><a href="/clearance-docs/it/guide/security.html">Security</a> - il modello completo di escalation di privilegi e ceiling.</li></ul>`,24)])])}const m=a(o,[["render",l]]);export{u as __pageData,m as default};
